// // This code implements a 7-segment display driver that sequentially displays four digits of a 28-bit input number on a single display. It uses a clock signal to cycle through each digit and update the corresponding 7-segment output. The digit selection is controlled by a 2-bit counter derived from the clock signal.
module top_module(
	input clk_i, 
	input [27:0] number_i, 
	output reg [6:0] seg_o, 
	output reg [3:0] an_o
    );reg [15:0] div = 16'b0; 
always @(posedge clk_i)
	div <= div+1'b1; 

always @(div[15:14], number_i) begin 	

	case(div[15:14]) 
		2'h0: begin 
			an_o 	<= 4'b1110; 
			seg_o 	<= number_i[6:0];
		end 
		2'h1: begin 
			an_o 	<= 4'b1101; 
			seg_o 	<= number_i[13:7];
		end 
		2'h2: begin 
			an_o 	<= 4'b1011; 
			seg_o 	<= number_i[20:14];
		end 
		2'h3: begin 
			an_o 	<= 4'b0111; 
			seg_o 	<= number_i[27:21];
		end  
		default: begin 
			an_o 	<= 4'b1111; 
			seg_o 	<= 7'b1111111;
		end 
	endcase 
end 

endmodule
